/// Coarse region name -> its region-lock ITEM name. The client resolves each to a live
/// open-state flag via `region_open_flags` (absent lock = region unlocked this seed).
/// Source: greenfield "<Region> Lock" naming (seed-independent, = regionOpenFlags keys).
pub const COARSE_LOCK_ITEMS: &[(&str, &str)] = &[
    ("Abyssal", "Abyssal Lock"),
    ("Ainsel River", "Ainsel River Lock"),
    ("Altus", "Altus Lock"),
    ("Ancient Ruins", "Ancient Ruins Lock"),
    ("Belurat", "Belurat Lock"),
    ("Caelid", "Caelid Lock"),
    ("Cerulean", "Cerulean Lock"),
    ("Charo's", "Charo's Lock"),
    ("Deeproot Depths", "Deeproot Depths Lock"),
    ("Enir Ilim", "Enir Ilim Lock"),
    ("Ensis", "Ensis Lock"),
    ("Farum Azula", "Farum Azula Lock"),
    ("Gravesite", "Gravesite Lock"),
    ("Haligtree", "Haligtree Lock"),
    ("Jagged Peak", "Jagged Peak Lock"),
    ("Leyndell", "Leyndell Lock"),
    ("Limgrave", "Limgrave Lock"),
    ("Liurnia", "Liurnia Lock"),
    ("Mohgwyn", "Mohgwyn Lock"),
    ("Mountaintops of the Giants", "Mountaintops of the Giants Lock"),
    ("Mt. Gelmir", "Mt. Gelmir Lock"),
    ("Rauh Base", "Rauh Base Lock"),
    ("Raya Lucaria Academy", "Raya Lucaria Academy Lock"),
    ("Scadu Altus", "Scadu Altus Lock"),
    ("Scaduview", "Scaduview Lock"),
    ("Sewer", "Sewer Lock"),
    ("Shadow Keep", "Shadow Keep Lock"),
    ("Siofra River", "Siofra River Lock"),
    ("Stone Coffin", "Stone Coffin Lock"),
    ("Stormveil", "Stormveil Lock"),
    ("Weeping", "Weeping Lock"),
];

/// location id -> fine region name (the tracker's grouping).
pub fn location_region_table() -> HashMap<u64, RegionId> {
    LOCATION_META.iter().map(|(id, r, _, _, _)| (*id, (*r).to_string())).collect()
}

/// location id -> coarse region key ("" = always accessible). In-logic keys off this.
pub fn location_coarse_table() -> HashMap<u64, RegionId> {
    LOCATION_META.iter().map(|(id, _, c, _, _)| (*id, (*c).to_string())).collect()
}

/// The DEFAULT progression surface: location ids this world's own progression may occupy.
/// A seed may override it via slot_data `progressionSurfaceLocations`; this is the fallback.
pub fn progression_surface_set() -> HashSet<u64> {
    LOCATION_META.iter().filter(|(_, _, _, b, _)| *b).map(|(id, ..)| *id).collect()
}

/// Missable location ids.
pub fn missable_set() -> HashSet<u64> {
    LOCATION_META.iter().filter(|(_, _, _, _, m)| *m).map(|(id, ..)| *id).collect()
}

/// coarse region name -> lock item name.
pub fn coarse_lock_item_table() -> HashMap<RegionId, String> {
    COARSE_LOCK_ITEMS.iter().map(|(r, l)| ((*r).to_string(), (*l).to_string())).collect()
}

#[cfg(test)]
mod generated_tests {
    use super::*;

    #[test]
    fn nonempty_unique_sorted() {
        assert!(!LOCATION_META.is_empty());
        assert!(LOCATION_META.windows(2).all(|w| w[0].0 < w[1].0));
        assert_eq!(location_region_table().len(), LOCATION_META.len());
    }

    #[test]
    fn coarse_keys_have_lock_items() {
        // every non-blank coarse key a location uses must resolve to a lock item
        let locks = coarse_lock_item_table();
        for (_, _, c, _, _) in LOCATION_META {
            if !c.is_empty() {
                assert!(locks.contains_key(*c), "coarse {c} has no lock item");
            }
        }
    }
}
